const msg = $input.first().json;

const texto = msg?.message?.text || msg?.message?.caption || '';

const from = msg?.message?.from || {};
const chat = msg?.message?.chat || {};

const nombre_cliente = [from.first_name, from.last_name].filter(Boolean).join(' ') || from.username || 'Cliente Desconocido';
const chat_id = String(chat.id || from.id || '');
const username = from.username ? '@' + from.username : 'sin_usuario';
const mensaje_id = String(msg?.message?.message_id || '');

const textoLimpio = texto.trim();
const textoSinEmojis = textoLimpio.replace(/[\u{1F000}-\u{1FFFF}]/gu, '').trim();
const esMuyCorto = textoSinEmojis.length < 3;
const esSoloPuntuacion = /^[.,!?;:\-_*#@%&/\\]+$/.test(textoLimpio);
const esSoloEmojis = textoSinEmojis.length === 0 && textoLimpio.length > 0;

if (!textoLimpio || textoLimpio === '' || esMuyCorto || esSoloPuntuacion || esSoloEmojis) {
  return {
    valido: false,
    chat_id,
    nombre_cliente,
    username,
    mensaje: '',
    mensaje_id,
    fecha: new Date().toISOString(),
    error: 'Mensaje no válido — muy corto, solo puntuación o solo emojis'
  };
}

return {
  valido: true,
  chat_id,
  nombre_cliente,
  username,
  mensaje: textoLimpio,
  mensaje_id,
  fecha: new Date().toISOString(),
  canal: 'Telegram'
};

const input = $input.first().json;
const raw = input.text || input.output || input.response || '';

const datosOriginales = {
  chat_id: $('Preparar Datos del Mensaje').item.json.chat_id,
  nombre_cliente: $('Preparar Datos del Mensaje').item.json.nombre_cliente,
  username: $('Preparar Datos del Mensaje').item.json.username,
  mensaje: $('Preparar Datos del Mensaje').item.json.mensaje,
  mensaje_id: $('Preparar Datos del Mensaje').item.json.mensaje_id,
  fecha: $('Preparar Datos del Mensaje').item.json.fecha,
  canal: $('Preparar Datos del Mensaje').item.json.canal
};

let clasificacion = {};
const categoriasValidas = ['reclamo', 'consulta_preventa', 'seguimiento'];

try {
  let cleaned = raw
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .replace(/^[^{]*/s, '') 
    .replace(/[^}]*$/s, '')
    .trim();

  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');
  if (start !== -1 && end !== -1) {
    cleaned = cleaned.substring(start, end + 1);
  }

  clasificacion = JSON.parse(cleaned);

  if (!categoriasValidas.includes(clasificacion.categoria)) {
    clasificacion.categoria = 'fallback';
  }

} catch (e) {
  clasificacion = {
    categoria: 'fallback',
    urgencia: 'media',
    resumen: 'Error al clasificar el mensaje'
  };
}

return {
  ...datosOriginales,
  categoria: clasificacion.categoria || 'fallback',
  urgencia: clasificacion.urgencia || 'media',
  resumen_llm: clasificacion.resumen || 'Sin resumen',
  raw_llm_clasificador: raw
};

