const data = $input.first().json;

const execution = data.execution || {};
const workflow = data.workflow || {};
const error = execution.error || {};

const nodo_fallo = execution.lastNodeExecuted || 'Desconocido';
const mensaje_error = error.message || error.description || 'Sin descripción de error';
const tipo_error = error.name || error.type || 'Error desconocido';
const stack = (error.stack || '').substring(0, 500);

let severidad = 'MEDIA';
let emoji = '🟡';

if (nodo_fallo.includes('LLM') || nodo_fallo.includes('Groq')) {
  severidad = 'ALTA';
  emoji = '🔴';
} else if (nodo_fallo.includes('Telegram')) {
  severidad = 'ALTA';
  emoji = '🔴';
} else if (nodo_fallo.includes('Sheets')) {
  severidad = 'MEDIA';
  emoji = '🟡';
} else if (nodo_fallo.includes('Trigger')) {
  severidad = 'CRITICA';
  emoji = '💀';
}

const fecha = new Date().toISOString();
const fecha_legible = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

return {
  fecha,
  fecha_legible,
  workflow_nombre: workflow.name || 'Ford Repuestos — Triage Telegram',
  workflow_id: workflow.id || '',
  execution_id: execution.id || '',
  nodo_fallo,
  tipo_error,
  mensaje_error,
  severidad,
  emoji,
  stack_trace: stack,
  resuelto: 'NO'
};

